foreach ($item in $images.GetEnumerator()) {
    $targetPath = Join-Path $PSScriptRoot "../$($item.Key)"
    $targetDir = Split-Path $targetPath -Parent
    if (!(Test-Path $targetDir)) {
        New-Item -ItemType Directory -Path $targetDir -Force | Out-Null
    }
    Write-Host "Downloading $($item.Key)..."
    try {
        Invoke-WebRequest -Uri $item.Value -OutFile $targetPath -TimeoutSec 15 | Out-Null
    } catch {
        Write-Warning "Failed to download $($item.Key): $_"
    }
}
Write-Host "Asset downloads complete!"
